// Retournez le résultat avec 'return'
// Bun supporte TypeScript nativement!

interface Result {
  message: string;
  timestamp: string;
  input: unknown;
}

const result: Result = {
  message: 'Hello from Bun!',
  timestamp: new Date().toISOString(),
  input
};

return result;

